// Rise 6.0 - ESP (add player from S0C to tracked list):
@EventLink()
public final Listener<PacketReceiveEvent> onPacketReceive = event -> {
    if (event.getPacket() instanceof S0CPacketSpawnPlayer) {
        S0CPacketSpawnPlayer s0c = (S0CPacketSpawnPlayer) event.getPacket();
        int entityId = s0c.getEntityID();
        UUID uuid = s0c.getPlayer();

        // Add to ESP target list
        if (!espedPlayers.contains(entityId)) {
            espedPlayers.add(entityId);
        }

        // Check if this is a bot (no tab list entry)
        if (!validPlayerUUIDs.contains(uuid)) {
            botEntities.add(entityId);
        }
    }
};

