package net.minecraft.network.play.server;

import net.minecraft.entity.DataWatcher;
import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import java.io.IOException;
import java.util.UUID;

public class S0CPacketSpawnPlayer implements Packet<INetHandlerPlayClient> {
    private int entityId;
    private UUID playerId;
    private int x, y, z;
    private byte yaw, pitch;
    private int currentItem;
    private DataWatcher watcher;
    private List<ItemStack> equipment;

    public S0CPacketSpawnPlayer() {}

    public void processPacket(INetHandlerPlayClient handler) {
        handler.handleSpawnPlayer(this);
    }

    public int getEntityID() { return this.entityId; }
    public UUID getPlayer() { return this.playerId; }
    public int getX() { return this.x; }
    public int getY() { return this.y; }
    public int getZ() { return this.z; }
    public byte getYaw() { return this.yaw; }
    public byte getPitch() { return this.pitch; }
}

